{
  // "web" | "mobile" | "whatsapp" | "voice" — the channel the user is on
  "channel": "web",
  // BCP-47 language code — "en" for English, "hi" for Hindi
  "language": "en"
}

{
  // ── PICK ONE action type — delete the other two before sending ────────────

  // select_choice: user tapped a quick-reply button
  //   "action": "select_choice",
  //   "choice_id": "<id>",     // from previous response → activities[].choices[].id
  //   "user_says": "<label>"   // optional — the button label for the transcript

  // send_message: user typed free text (only when disable_input is false)
  //   "action": "send_message",
  //   "text": "<user typed text>"

  // pick_item: user selected from a dynamic list (course picker, etc.)
  //   "action": "pick_item",
  //   "picker_id": "<id>",     // from previous response → activities[].picker_id
  //   "item_id":    "<id>",    // from previous response → activities[].items[n].id
  //   "item_label": "<label>"  // from previous response → activities[].items[n].label

  // ── Active example (select_choice) ─────────────────────────────────────
  // "select_choice" — user tapped a quick-reply button; choice_id MUST come from the previous response
  "action": "select_choice",
  // From previous response → activities[].choices[].id  (NEVER hardcode in real code)
  "choice_id": "REPLACE_WITH_CHOICE_ID",
  // Optional — the button label shown in the UI (for conversation transcript)
  "user_says": "REPLACE_WITH_BUTTON_LABEL"
}

{
  // "web" | "mobile" | "whatsapp" | "voice" — the channel the user is on
  "channel": "web",
  // BCP-47 language code — "en" for English, "hi" for Hindi
  "language": "en"
}

{
  "action": "select_choice",
  // choice_id from Step 1 response → activities[1].choices[].id
